package Lec_19;

public class Substring_Demo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		String s = "codingblocks";
		System.out.println(s.substring(2)); //index 2 se entire string print ho jayega...
//		4th index print nahi hoga
		System.out.println(s.substring(1,4)); //1st index se leke 3rd index tak ka content print hoga
	}

}
